import{_ as t,o as e,c as r,a3 as a}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"39A. Recall Without Returning To Workplace","description":"","frontmatter":{"title":"39A. Recall Without Returning To Workplace","eba":"Doctors in Training 2022-2026","topics":["hours","overtime","rosters","on-call"]},"headers":[],"relativePath":"ebas/doctors-in-training/hours-of-work/39A-recall-without-returning-to-workplace.md","filePath":"ebas/doctors-in-training/hours-of-work/39A-recall-without-returning-to-workplace.md"}'),i={name:"ebas/doctors-in-training/hours-of-work/39A-recall-without-returning-to-workplace.md"};function n(l,o,s,c,h,u){return e(),r("div",null,[...o[0]||(o[0]=[a('<h1 id="_39a-recall-without-returning-to-workplace" tabindex="-1">39A. Recall Without Returning To Workplace <a class="header-anchor" href="#_39a-recall-without-returning-to-workplace" aria-label="Permalink to &quot;39A. Recall Without Returning To Workplace&quot;">​</a></h1><p><strong>39A.1</strong> The provisions of this clause 39A are to be read in conjunction with <a href="/eba/ebas/doctors-in-training/hours-of-work/40-telephone-calls-to-doctors-outside-of-working-hours.html">clause 40</a> (Telephone Calls to Doctors Outside of Working Hours).</p><p><strong>39A.2</strong> Where recall to duty can be managed without the Doctor having to return to their workplace, such as by telephone or computer, the Employee will be paid a minimum of 1 hour at the appropriate overtime rate for each occasion, provided that multiple recalls within a discrete hour will not attract additional payment.</p><p><strong>39A.3</strong> Remote recall should only occur where the Doctor is rostered on-call and in accordance with <a href="/eba/ebas/doctors-in-training/hours-of-work/40-telephone-calls-to-doctors-outside-of-working-hours.html">clause 40</a> (Telephone calls to Doctors outside of Working Hours) below.</p><p><strong>39A.4</strong> Doctors who undertake remote recall will submit information to the health service as required within the timeframe set by the health service.</p>',5)])])}const g=t(i,[["render",n]]);export{d as __pageData,g as default};
